import React from 'react';

const Home = () => {
  return (
    <header className="bg-white shadow-lg border-b border-gray-100 sticky top-0 z-10">
      <div className="container mx-auto px-4 sm:px-6 lg:px-8 py-4 flex justify-between items-center">
        {/* Application Title/Logo Area */}
        <div className="flex items-center space-x-3">
          {/* Logo Icon (Using a simple SVG for a clean look) */}
          <svg 
            className="w-8 h-8 text-indigo-600" 
            xmlns="http://www.w3.org/2000/svg" 
            viewBox="0 0 24 24" 
            fill="currentColor"
          >
            <path d="M7 3h10a2 2 0 012 2v14a2 2 0 01-2 2H7a2 2 0 01-2-2V5a2 2 0 012-2zm0 2v14h10V5H7zm2 2h6v2H9V7zm0 4h6v2H9v-2zm0 4h4v2H9v-2z"/>
          </svg>
          
          {/* Title */}
          <h1 className="text-3xl font-extrabold text-gray-900 tracking-tight">
            NoteStream
          </h1>
        </div>
        
        {/* Placeholder for User/Settings (as per the "no add to new" instruction) */}
        <div className="flex items-center space-x-4">
          <button 
            className="text-gray-500 hover:text-indigo-600 transition-colors"
            aria-label="Settings"
            title="Settings"
          >
            {/* Settings Icon */}
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
              <path strokeLinecap="round" strokeLinejoin="round" d="M10.325 4.317c.426-1.748 2.37-1.748 2.796 0l1.325 5.41a2 2 0 001.594 1.258l5.772.585c1.77.179 2.196 2.589.65 3.513l-4.225 3.085a2 2 0 00-.77 1.954l.43 5.45c.18 1.767-1.55 2.593-2.97 1.55l-4.71-3.417a2 2 0 00-2.31 0l-4.71 3.417c-1.42 1.043-3.15-.383-2.97-1.55l.43-5.45a2 2 0 00-.77-1.954l-4.225-3.085c-1.546-.924-1.12-3.334.65-3.513l5.772-.585a2 2 0 001.594-1.258l1.325-5.41z" />
            </svg>
          </button>
          
          <div className="w-8 h-8 bg-indigo-200 rounded-full flex items-center justify-center text-sm font-semibold text-indigo-800">
            JD {/* Placeholder for User Initials */}
          </div>
        </div>
      </div>
    </header>
  );
};

export default Home;
